sercontent.com/a-/ALV-UjUwlwT93XJD01Io6aTBDV8IEhCv4s-Ivv4SxTUqgsvkotdA0-G0=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Great Hospitality'' Really had a great time playing there with my partner. We booked an hour with two paddles. Paddle rental was 30k/each. The team was welcoming, they recently opened so facilities is quite new! Price listed in photo attached.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3Lmjm7cjTVMdWOMZAq_YvibY37JvDF4T7F0HxC2NUsXBv6Iekl7_DncUa2-n1sry8AAHe3ufnkAOsrc_IECR8Z1gBTnoGXd4NeTKTS-VJgmtBM2Xi0ETMQTWtc2Z2b52O7FLXVMtbwmjuR=k-no"], "When": "2026-4-14"}, {"Name": "Michael Palmer", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKeOT6z1-JzEpFWkRUR7oeSqVWtFzzWg-Fo3SkDJIM90DNXHw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "High quality pickleball courts close to tourist area. 8 courts in excellent condition with good lighting and other facilities. Excellent service from the owners and staff. Can also rent bats here.", "Images": null, "When": ""}, {"Name": "Ben Gorry", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLf-XbF1v9N5cStVCzCATnTLSPrb4BAdB49hGXbz4RV2v3aOg=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Amazing court and facilities!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn255S-fvo2nQI_E2Lh05ZBQB5DBPPP3oF3Jz3R5A9MI7toZKXRlqUIqSwNJ7WbpoVNWJrTV_UL6BkMSHu8XlRmfa8Clf5wuYN2dn7uvex09DVe8X_PsjZOeVC7bYCu1tL5veNmrbaD35pI=k-no"], "When": "2026-4-2"}, {"Name": "Quyết Nguyễn", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXEYKU5ec0X2AhXmGM0E0Dgc6ea88LTpz1gGEhg6fWBgbN3jpue=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân mới tinh chuẩn quốc tế. Nhân viên nhiệt tình", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3UmGoTqhxQY2MapRi-Kd6-qq1Xe3nVe_sXiZANcyzuOO-Jzf7L5wOWQfnwyL6IyhmSqO1optwQ6hu0tN7nMFTL_vVr4rRi-N_rQnL_rsESDbF3jPPs-vNnMuYRcHq7Mq8HYnucM1zl7fQ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2R9pHQEMf44ee8cyAy0OKIBS1cgBi0sJaQaWgaj8BLszH9YK1I4CmqEwTXFqBbB-P69TpPdqgobX1FBDoQXpIc-faI-_xJaVgwa92SSr9yqld3axnua1t2AZcnZQBn_PEscT16qm3IGwpv=k-no"], "When": "2026-4-29"}, {"Name": "terry kochanowski", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWZN8cAqxshZ4jDEOJyqtz0QNpUI5oLonpHxQD6vz5yYlp9cj-T=s120-c-rp-mo-ba2-br100", "Rating": 2, "Description": "Nous avons joué 40 minutes durant les créneaux du matin et loués 2 raquettes. Ventilateur mal placé donc ils faisaient très chaud. Ils nous ont demandé 220k ce qui est une tentative de scam parce que je suis blanc, mais je connais les prix du marchés. C’est la dernière fois pour moi ici. Être honnête vous permettrez de fidéliser vos clients. Conseil de blanc", "Images": null, "When": ""}, {"Name": "Alexander", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLBUIP6busdrv-EZMhYXX8XFuQlwxyo5SshB-75wecjF2uOjA=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Це був мій перший раз, мені сподобалося. Персонал дуже приємний.", "Images": null, "When": ""}]'::jsonb, '{}'::jsonb, NULL, ARRAY['Pickleball court'], NULL, '06:00', '22:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
