VksvvnzScPe8-0U0DTTtJ6DziIrDfSBZ0MFpzS3Skq0B5B-ILlLhUmNFP0nURXfM=w397-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=0Y67vVekJgsG2LufMO2QBQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=94.02428&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["6 a.m.–9 p.m."], "Monday": ["6 a.m.–9 p.m."], "Saturday": ["6 a.m.–9 p.m."], "Sunday": ["6 a.m.–9 p.m."], "Thursday": ["6 a.m.–9 p.m."], "Tuesday": ["6 a.m.–9 p.m."], "Wednesday": ["6 a.m.–9 p.m."]}'::jsonb, '[{"Name": "Joel Lüthy", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWo2zEVNlOiZFXUByNAKSb3KpxIyP2wH0XoRj3sEU9PmepNHaGm=s120-c-rp-mo-br100", "Rating": 1, "Description": "Unfortunately very unfriendly people there. They told us that we are not welcome for no reason. Do not visit.", "Images": null, "When": ""}, {"Name": "Honest Evaluator", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWRTHjeBNz0rJxFJvTbab2HJqAOR1IbWS6aCHnECxlIsO4mMD8=s120-c-rp-mo-ba4-br100", "Rating": 2, "Description": "- New court\n- Uneven surface\n- Not great for play!", "Images": null, "When": ""}, {"Name": "Руслан Владимиров", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUBG9gTuS4xC9LMnvW5vVAzKJn45Ht6MaJcgYIMI1gFMmRJv-0H=s120-c-rp-mo-br100", "Rating": 5, "Description": "Very nice pickleball", "Images": null, "When": ""}, {"Name": "thương võ", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL8u7UMFZcpWTabK83jT4vtmzSDSEWynTR3Qn6XljPM_HpMZg=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp a chủ nhiệt tình đặc biệt phòng thay đồ nhà tắm và toaloet quá sạch sẽ xịn sò.10 điểm", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2xyQI9G8d2FINLN0u9DtcnTsKw04ssTMIOeVOgVPzcAm4MqlK547PazVclyuo8B0hu4ghLoggok4ZaUX4QKQOoxecGvRd9Xkw8hgNaeKVYAeM5mQneLEGp_wIViHIVTtLrgHuvDFKigCE=k-no"], "When": "2026-1-14"}, {"Name": "Đức Anh Lê", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJUB1btM2BcfT4OiAUPsaNWg2ibh68K_