INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('T-ARMY PICKLEBALL', '173 Lê Quang Đạo, Ngũ Hành Sơn, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Ngu Hanh Son', 16.050208, 108.245594, 4.6, 16, '+84 904 383 385', 'https://www.google.com/maps/place/T-ARMY+PICKLEBALL/data=!4m7!3m6!1s0x31421744df3aa873:0x4c96835b0f819079!8m2!3d16.0502077!4d108.2455945!16s%2Fg%2F11z4stf3_y!19sChIJc6g630QXQjEReZCBD1uDlkw?authuser=0&hl=en&rclk=1', NULL, 'ChIJc6g630QXQjEReZCBD1uDlkw', 'https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=yhVYvi_Sp3RPk7DVFX9REQ&cb_client=search.gws-prod.gps&w=408&h=240&yaw=83.37674&pitch=0&thumbfov=100', '[{"title": "All", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=yhVYvi_Sp3RPk7DVFX9REQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=83.37674&pitch=0&thumbfov=100"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEsJoW237v0nW0CMmgetzDRxwcZ06AOL6CvMNM8v25AiE8I0Gl1VFP9adKjpH1cS9lzRzpFSgijCtstuznIBOBinLYKdGlE3WCogFi0XFDVUpO-KpiGT_Bx-Ddi-aMfFgLch11yJkCIdm0B=w224-h398-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEd1El0a11902PRdpHGXKpdmB4et5SGl0HSUygN8FvBqpSR5d3T15_DfdSnJQCe-8HeRMzjY5m9_5385SowjYqw5XV6BCPQ4fgXtFzkLKdsMVDEG2p6mmE5dbc3lv1tUrrlnHB1uTKOnrmL=w530-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=yhVYvi_Sp3RPk7DVFX9REQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=83.37674&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–11 p.m."], "Monday": ["5 a.m.–11 p.m."], "Saturday": ["5 a.m.–11 p.m."], "Sunday": ["5 a.m.–11 p.m."], "Thursday": ["5 a.m.–11 p.m."], "Tuesday": ["5 a.m.–11 p.m."], "Wednesday": ["5 a.m.–11 p.m."]}'::jsonb, '[{"Name": "Kumi 720", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKSswExKjctrgKbPVYCfQn-BqMY8MJFtlSHrL_0xl9wKa6VzQ=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "New opened pickle ball cort. Here is near our hotel. This is our first experience to play pickleball here. It was very fun, although for me beginner.", "Images": null, "When": ""}, {"Name": "RoddyRoadz", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocI77ldbcRAK-VD7oeVxtbCdQwiQ76PLNvoNFRSM1nPoh-rZuw=s120-c-rp-mo-br100", "Rating": 5, "Description": "⭐⭐⭐⭐⭐\n\nTarmy Pickleball Place is absolutely amazing! I had such a great time playing here. The courts are well-maintained, and the overall vibe is fun and welcoming.\n\nThe staff — especially the girls — are incredibly friendly and make you feel comfortable right away. Their positive energy really adds to the experience.\n\nAnd strangely enough, they have the best-tasting coconuts I’ve had! Perfect for refreshing electrolytes after a tough game. It’s the ideal way to cool down and recover.\n\nI highly recommend this place to anyone who loves pickleball or just wants a fun, relaxed atmosphere. I’ll definitely be back! 🏓🥥😊", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn32uT_HXxiXdeDw4w-jULF4bji2R8hlYsJCL0nORSvM4SALXqZGE9gz835Z1x-rfbab3K_wp5TkesfW9aj5dG-IKIKm2Hkadb97A7UKPhDlH8IU9cV8yN8dSlSxDp7Cv6JhHEy6SebN3XiL=k-no"], "When": "2026-4-21"}, {"Name": "Jesse Kerckaert", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUda_xb37ZMcTeaQQFWPwhdAnj2MQ4HgipkGTD5wKYwRMPj5vz8=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Nice courts, very affordable, and you can rent padels and balls here", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2818ACGyjSaVeg6z89-8c0vjbYCYNEJ3yKgn5JpuStOh4zTIR-gSJcpezoPAJKKWS3uaCRICRn9jMHlULz5G2l6xBn56F6b-2ECARzx8TbhnLsLNmi0WpxJJ0eFhFOjeK_ekNKE53lZbrB=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1XC2QD8x21HOyocHd_ZDTSHIuVUx8-A29TBb6dYSVmWe8wJkpJU1UWKnETkM0tmBLauzA2IVbl7z4WZbWZeaWQLum_ZecniGCBPIuvNJmVFJwZ2uS-DIKgpukzxdqAwmD0wox5Dz7v6Squ=k-no"], "When": "2026-4-15"}, {"Name": "Hang Aut", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLqIHDs_6e_DVdfEKRxILIRhrCYRaNhH54NWegI37I-bZ8aew=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "The heat on this court is unbearable. There is absolutely no ventilation and zero airflow, making it feel like a literal oven. But the worst part is the location there is a trash dump right behind the fence. You are forced to breathe in a disgusting, rotting stench the entire time you’re playing. No fresh air, no fans, just stifling heat and the smell of garbage. It’s honestly nauseating. Avoid this place at all costs!", "Images": null, "When": ""}, {"Name": "duc nghia", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL69QtI_ony7eNU1vDyWUERqeDvEFU8DoPoCyxC4Vt6Sei4yQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "", "Images": null, "When": ""}, {"Name": "Ace of Lion", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU2x8_kROG9jMB8SCZvMVQXtZrDgIpaSe3VuitG_oFZCY8T3TmTNg=s120-c-rp-mo-ba7-br100", "Rating": 4, "Description": "피클볼 시설중 다낭에서 가장 크고 넓어서 좋은듯. 특히 접근성이 뛰어남.이용료는 오전5시부터 오후4시까지 160,000동, 오후4시부터 오후 11시까지는 220,000동 입니다. 라켓 대여는 20,000동 공은 프리입니다.\nThis pickleball facility in Da Nang seems to be one of the largest and most spacious. It’s especially great because of its excellent accessibility.\nThe usage fee is 160,000 VND from 5:00 AM to 4:00 PM, and 220,000 VND from 4:00 PM to 11:00 PM.\nPaddle rental costs 20,000 VND, and balls are provided for free.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn12u9ccoDy3XmtaQNfcWJ8QKf2pOqhR4O0x4hx81_MAmehqwPkimA4_wp39fZPqb4GeSFmW6ScVrj2zkC5M_VT53OyQkj30rh0j3hWNZ8BfrAop0la8YtuHWOQMK1FopWyHFRr0Ai7IXdM=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3l8SwEZ5n82uQGSlksax1E_g1epu0iEnzsfLzNtYAjPkLcg6cNVtTAAR4hep2pKXYgKQTkXaeYOM1GDM8M4gGg3Si-x7M287yhLJgHAnkudocCKblqql7DRiy4CHG-yrnNEJ2JhpbKJePr=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1zQrH-eag15qbpeSiWVYqTlc9TE_Vny_5FhfUjrZQwCqTxBBt7l3xuBPOEEyIxQYFG7lDJeEs0msaufTggeWnL_ebf6UFro3Uy0xuPZklyRWkhiShONh6ndIpm6B1jD_8vYCaGdb30Stu6=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn00ScUQOjIuYKnmMHNc7K8qGCecRNt5OfE8joHNMVV33sylkKgGFYyDScver_q_Oid12nwVY3RD4WaOtOFdxyq8fCgQ80-cfhRND_K27H8U5w5pyi7F9g52Lq0z7zcljdEBMK_zd9Wgh20y=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn27s7m6jd4UpSCcttuo48nMb0vN0KQc9areQQxH9m1coF-fi83Xdi3WcQKBdFVeWgExesYRhkaPRD_-deyL0MIxh9onF55h91Z0rEZ1Bn2K7IilSwnjDiYpq0bzTeYaRkSYloHPzAx4zcE4=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0l8JwpyYeSsIReRP3nZ8B_y46cObkZ25pcPneEzc_ZFxR33Zue3z7JeI6aTS2jE63Z2PmLsJAqZg3jLUOmXLs_ko_OCaoejnDiH44cioU3I3CdD3RGDDTzPU6CfWhR793YwLekV6Lq6G_j=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1iTm2SxuoX4dC3ppscTZBBDWMLplbDvuJdS1caztgDG5oBVp1SPT8j8bZB394XnEeAv90FkEztdz9lXa77bBZb7UK4o18pa8d6JO9sJ6XFBnRYdrmFXfBax6clUczYhjXzKbtaTSMn9fQX=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1waUxKZ6iXmVq15r7zSULkFXk9rX8GIoBJrtyQKqEjZUdPrZtUWflWInZWHjnHg6AfISA0DrtBMWhFZMt2v2GCP8B4rGCKQsPXDBBGMP6ZxS5K4GheeEkPlcW40XI1hX6UPBdbMzU0CclM=k-no"], "When": "2026-4-20"}, {"Name": "TX.P", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVLy8RwzlBVUSpcpn8rUjb85ahBfc-p2Z0rxPV6i-izg6rxlcPH=s120-c-rp-mo-ba5-br100", "Rating": 4, "Description": "zapłaciliśmy 220k/h, co wydaje się bardzo wysoką ceną.\n\nDużo kortów otoczonych siatką więc piłka nie ucieka daleko.", "Images": null, "When": ""}, {"Name": "Công Nguyễn", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIU1oNQSkCH2gh2L2NR9Tfl_o7n0IEaGZX3jNom4swdxIeZTB6b=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Sân mới, đẹp và thoáng mát, giả cả cũng phải chăng mặc dù nằm ở khu phố Tây. Sẽ ghé chơi social thường xuyên", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2sbtd8nrWwEV-OLuUIBhaUgUQ2PODyVCBW98jm92_YI01emjsf5nxp4Yph-CLRqdBKiLtIohzMWd-c6gxksvJuwMQ3zodE4NfYKnki6KGuy5s