googleusercontent.com/a/ACg8ocIKF78sU5mAwRnSRMlRU-neo2J8TAp44aU2ypGAf-FLzOXnAQ=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Klasse Ort zum Pickleball spielen.\n\nWir wurden sehr freundlich in Empfang genommen und haben die schöne Atmosphäre sehr genossen.\n\nDie Anlage ist ganz neu und braucht sich nicht verstecken.", "Images": null, "When": ""}, {"Name": "Minh Phuong Tran", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWnxqKHFSnzrlG4Cvk2KAzxOZPHTL0xStBl5RlJItUPAu5ZiO2A=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân rộng, mát. Lên lúc nào cũng có kèo mà ae thân thiện nữa.", "Images": null, "When": ""}]'::jsonb, '{}'::jsonb, '[{"id": "service_options", "name": "Service options", "options": [{"name": "Onsite services", "enabled": true}]}, {"id": "amenities", "name": "Amenities", "options": [{"name": "Gender-neutral washroom", "enabled": true}]}, {"id": "crowd", "name": "Crowd", "options": [{"name": "LGBTQ+ friendly", "enabled": true}, {"name": "Transgender safe space", "enabled": true}]}, {"id": "payments", "name": "Payments", "options": [{"name": "NFC mobile payments", "enabled": true}]}, {"id": "parking", "name": "Parking", "options": [{"name": "Free parking lot", "enabled": true}, {"name": "Free street parking", "enabled": true}]}]'::jsonb, ARRAY['Transgender safe space', 'LGBTQ+ friendly', 'NFC mobile payments', 'Gender-neutral washroom', 'Free parking lot', 'Pickleball court', 'Free street parking', 'Onsite services'], NULL, '05:00', '21:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular