INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('VQ Fitness & Pickleball Club', '273/1 Nguyễn Công Hoan, Hoà An, An Khê, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Hoà An, An Khe', 16.047739, 108.177003, 4.8, 46, '+84 777 589 758', 'https://www.google.com/maps/place/VQ+Fitness+%26+Pickleball+Club/data=!4m7!3m6!1s0x3142190c69f5ca89:0xbc05bdda80f3fe53!8m2!3d16.0477387!4d108.1770026!16s%2Fg%2F11y49_fvvx!19sChIJicr1aQwZQjERU_7zgNq9Bbw?authuser=0&hl=en&rclk=1', 'https://www.vqfitness.club/', 'ChIJicr1aQwZQjERU_7zgNq9Bbw', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFnbCguiqjqNgzAwEJhV1PqwjvklSI3uRCd3d-sUpZzvNDTn3BVH2jzWToYQyC9o9GJL-e4l23CCDrL3i447QWRWTA5spzarA-pVi2fGEMETwLTUnds7Pm8siwb-i3SB_xyG1AXapVZ5Y5T=w408-h271-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFnbCguiqjqNgzAwEJhV1PqwjvklSI3uRCd3d-sUpZzvNDTn3BVH2jzWToYQyC9o9GJL-e4l23CCDrL3i447QWRWTA5spzarA-pVi2fGEMETwLTUnds7Pm8siwb-i3SB_xyG1AXapVZ5Y5T=w447-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAE-3ukKzk57aSi0QqfuBS0KSeBaK0PLb9cOS515qhcGqCDYRetxqRiMO71NoiX5bra5vhGXrW5eHhVOKcWNtnM-SGQ_-0bxPsuXSLIcn63tj4Jr95o4Fem95ohIkQmqenRlaJ2_XynKMXs=w408-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=MqxT-_RugnSQJFLQxsdYkA&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=6.7744026&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Andee Brooker", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLiNv9Sbcn-KqE4eLw2V8XJn3AR5rPEOmimtSNNkJ7ImY7cyg=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Thank you derek for showing me a great time  at VQ pickleball. i can’t wait to come again. the Vibes are so greattttt", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1o2EcPvKdlmzF6mPn_FlNnKMCHPbihn74XL3bFT1IKWVk0yooapp7mq1X7vxswTL8HmY0xzk-wLb5jJPeeyg-p8saZLRFoIoTsff9v3Y6KrNcrRzoAdfplbvn8kyxHTsmD_x_raQ=k-no"], "When": "2024-8-8"}, {"Name": "Kevin Law", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUaBDEOiIqJ2A9OExLdrk1vnQW_8zmlpTIY0IteVjR2CUbM77zI=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Thank you Derek at VQ fitness for bringing me on to play pickleball. See you on the courts!", "Images": null, "When": ""}, {"Name": "Phúc Nguyễn Văn", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUXlv-xpvIwRyJ4c_IWcL4ozqTkw_6JkEe76PkgpM8Z6anpOhAt=s120-c-rp-mo-br100", "Rating": 5, "Description": "Giá thuê sân quá hợp lý so với chất lượng nhận được. Vị trí rất dễ tìm và có chỗ đậu xe rộng rãi. Luôn có bóng và vợt cho thuê nếu cần. Mình không tìm thấy điểm nào để chê ở đây, xứng đáng 5/5 sao!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1bRUWNw2jrzjFK_QorjYfcdAUuD98Ni2-dCKSWhVY9eRokT1opsyKdAdujTbk5tzHbaPP8Wvji2uFYnKxuiQeIEIIYm5hsr06qG0uZOtE4fJ1lynoKTpsBy1MFB--ZMGLzqdkpoHbVseT6=k-no"], "When": "2025-12-12"}, {"Name": "Kham Thuan", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLzKsX4qHhq3P1-n45eH4PbXrU_ahbUYWAZLCRbh0Osf9bW1BQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân chơi Pickleball yêu thích của mình! Không khí rất vui vẻ, cộng đồng người chơi giao lưu thân thiện. Dễ dàng đặt sân và giá cả hợp lý. Cho 5 sao vì sự chuyên nghiệp và không gian tuyệt vời này.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2GZzyN_zKsdpcBpbaMD6-21ShrNwWLc5r12UBEDCyKqs0ZxdhUPxcbS2knftRtoS1NSaSbEcqh0G0WyhqFnyC-edgbDbf-WGZvDYu6h3I5UKpCdwLzufX2pszFY4yApDmgKuSGNYyRA00=k-no"], "When": "2025-12-12"}, {"Name": "Duyên Nguyễn Thị", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUwqYKhM3LYYSyUIz6mChbi_TTI1HlM38-_5i6gJhKQwHdho_o7=s120-c-rp-mo-br100", "Rating": 5, "Description": "Đây là nơi gia đình và bạn bè mình thường xuyên đến để giải trí cuối tuần. Sân sạch đẹp, không gian ngoài trời và rong nhà luôn đảm bảo trải nghiệm chơi tốt nhất. Rất thích hợp cho cả người mới chơi và những người chơi chuyên nghiệp!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0ygHyYMKrBXyV9TCwrLQ4c6LOgJd1CjPFVFgZrlehe6FB2qn_isBwBeLC6pu9FuoO3SxdhWex61hUDki6KtwyD2zWpSV8neWGYzTEdtDd-SscX-Qb783AdRDx3oVgYgGZbc626GmdLYoXv=k-no"], "When": "2025-12-12"}, {"Name": "Nhi Hải", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUg7v4yS0iCJPU0G0kTZuF_LxstvBJpjoitqhB39XeUvkENAX0i0A=s120-c-rp-mo-br100", "Rating": 5, "Description": "Ấn tượng nhất là thái độ phục vụ của nhân viên, rất nhiệt tình hỗ trợ từ khâu đặt sân đến lúc mượn vợt 🥰🥰🥰🥰 Rcm mạnh cho mnguoi tới trải nghiệm nhaaaaa", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0ofvYoErfAgf57clxJujtREmm6-23LZg8rKxOih6V5bip2znbZRLSaRY5wrJa19j37Tm7eWr32189cwQ1I03EO64aQS4k8jFyzEI9nQvIeeixhB6T-ZFGZQ-WjXc1NhDRQbUEteLsXaqD7=k-no"], "When": "2025-12-30"}, {"Name": "Huy Triệu Cao (Kouhee)", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjW0sP3ldy099b5igdWW3mlBDTwXKKFdS4asHi-UbszbxmlZKHId=s120-c-rp-mo-br100", "Rating": 5, "Description": "💯 5 sao không phải bàn cãi! Sân Pickleball ở đây cực kỳ chất lượng, mặt sân phẳng, lưới căng chuẩn, ánh sáng ban đêm tuyệt vời. Không gian thoáng đãng, mình và bạn bè luôn có những trận đấu hết sức sảng khoái. Rất khuyến khích cho mọi người yêu thích Pickleball!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2xGORoAMVKwA2cGKffmNYF2-0HuJeQ2LGTXKlhi9A5TljETYtcaeOFvQawQhDRPKqU0I_VWRTHPe-7gLG0o5O5xcZxYrjOg1TaRD7Ed5Q603UViTm4ULiLXcltrgMhlfOihTX0iImoGQM=k-no"], "When": "2025-12-12"}, {"Name": "Hoài Nguyễn Tô", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJXXWIggIVqdrIj3uE8OHn8JtBBWcGRh4JK2NA9GtLdVRXt1g=s120-c-rp-mo-br100", "Rating": 5, "Description": "Trải nghiệm tuyệt vời! Sân luôn được giữ gìn sạch sẽ, nhân viên thân thiện và hỗ trợ nhiệt tình. Có khu vực nghỉ ngơi, nước uống đầy đủ. Là địa điểm lý tưởng để luyện tập và giao lưu. Chắc chắn sẽ quay lại thường xuyên!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn39V8NSzafTCdTd8I7Q4ZdC1PlUgc9Tm8uyPhY0Z9l3TfOFytKwn3L3PjUD1I6LNRz9DJsn7g0QMWeKMA99ud12YTFR6aAs0adf9BXQ1Q-eAK-cgKPsgN4vlLZZtAnoLVg6W1x1-xMcMte8=k-no"], "When": "2025-12-12"}]'::jsonb, '{"Friday": {"10": 14, "11": 19, "12": 22, "13": 20, "14": 21, "15": 21, "16": 30, "17": 47, "18": 61, "19": 69, "20": 64, "21": 69, "4": 0, "5": 16, "6": 26, "7": 25, "8": 19, "9": 13}, "Monday": {"10": 19, "11": 29, "12": 27, "13": 28, "14": 22, "15": 26, "16": 33, "17": 60, "18": 85, "19": 100, "20": 89, "21": 80, "4": 0, "5": 11, "6": 14, "7": 17, "8": 14, "9": 15}, "Saturday": {"10": 19, "11": 23, "12": 30, "13": 40, "14": 47, "15": 53, "16": 47, "17": 39, "18": 32, "19": 33, "20": 42, "21": 50, "4": 0, "5": 19, "6": 20, "7": 19, "8": 19, "9": 19}, "Sunday": {"10": 26, "11": 29, "12": 32, "13": 28, "14": 21, "15": 27, "16": 33, "17": 46, "18": 50, "19": 48, "20": 42, "21": 46, "4": 0, "5": 19, "6": 22, "7": 27, "8": 26, "9": 25}, "Thursday": {"10": 32, "11": 44, "12": 50, "13": 41, "14": 34, "15": 38, "16": 45, "17": 53, "18": 69, "19": 70, "20": 71, "21": 66, "4": 0, "5": 21, "6": 19, "7": 15, "8": 20, "9": 21}, "Tuesday": {"10": 27, "11": 33, "12": 44, "13": 45, "14": 42, "15": 44, "16": 52, "17": 64, "18": 69, "19": 72, "20": 61, "21": 64, "4": 0, "5": 23, "6": 19, "7": 17, "8": 17, "9": 20}, "Wednesday": {"10": 23, "11": 26, "12": 36, "13": 35, "14": 29, "15": 22, "16": 28, "17": 41, "18": 61, "19": 72, "20": 76, "21": 73, "4": 0, "5": 17, "6": 20, "7": 19, "8": 20, "9": 20}}'::jsonb, NULL, ARRAY['Athletic park'], NULL, '05:00', '22:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.a