INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('GreenZone Pickleball', '75 Nguyễn Đình Thi, Hòa Xuân, Đà Nẵng, Vietnam', 'Da Nang', 'Hoa Xuan', 16.019664, 108.236344, 5.0, 21, '+84 866 191 192', 'https://www.google.com/maps/place/GreenZone+Pickleball/data=!4m7!3m6!1s0x314219215ac1c523:0x121d20d254b02869!8m2!3d16.0196638!4d108.236344!16s%2Fg%2F11yzc60xft!19sChIJI8XBWiEZQjERaSiwVNIgHRI?authuser=0&hl=en&rclk=1', 'https://www.facebook.com/GreenZonePickleball/', 'ChIJI8XBWiEZQjERaSiwVNIgHRI', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFlfXhyAPyF4vBG0PKVT7aUCyHsr-btK5p2u9xjVbIrcR6JFHudaVX_DeF1alz7TSl1lXMSuY87o4H1SyzCmj4lQpirQbE0GhqJ9ckSjLTe6IksbUMnAdaIrCdfYNsPhs6hY9RQoxCC9xpY=w426-h240-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFlfXhyAPyF4vBG0PKVT7aUCyHsr-btK5p2u9xjVbIrcR6JFHudaVX_DeF1alz7TSl1lXMSuY87o4H1SyzCmj4lQpirQbE0GhqJ9ckSjLTe6IksbUMnAdaIrCdfYNsPhs6hY9RQoxCC9xpY=w529-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFlfXhyAPyF4vBG0PKVT7aUCyHsr-btK5p2u9xjVbIrcR6JFHudaVX_DeF1alz7TSl1lXMSuY87o4H1SyzCmj4lQpirQbE0GhqJ9ckSjLTe6IksbUMnAdaIrCdfYNsPhs6hY9RQoxCC9xpY=w529-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=LD9d9qdLqlqalq1mtb_lXw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=126.16453&pitch=0&thumbfov=100"}]'::jsonb, '{}'::jsonb, '[{"Name": "Xupu", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVvjAmULVvOKHAydrb20sL33uRtcKuxozU0o_80JlC5p3CJYQKI=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Sân đẹp, nhân viên btri sân bãi nhanh nhẹn, linh hoạt. Cộng đồng đánh ở đây khá vui, nào set kèo đánh giao lưu toàn gặp mấy khứa hài nhưng chất phết nhé. Nói chuyện tán gẫu tí cũng ok lắm. Nước non ở đây làm cx oki, có bán cả phụ kiện đánh pick nên tiện mua luôn. Cho 5 sao liền", "Images": null, "When": ""}, {"Name": "Tấn Thông Ngô", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU7b_QCmM5jBN125EOwnOdiBA2kybR-Vhv3t9rO_ORCUR9A_6K-HQ=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Bên này có phân khu nhà vệ sinh đỉnh vlin, tưởng đi ksan luôn á. Khách du lịch ghé đây chơi cũng tiện lắm, vừa chơi pick mà lại còn có chỗ tắm rửa thay đồ sạch sẽ. Hài lòng lawmsm!!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0cONolGBK6G4Tx5Doq1MuqBuErTI5FrCSBl1QTT-l8-yph2HZka_p9wN6RYNXoi7AYCjHe53Mr_7AWZxeq_GvhAVrHoBHUgBU60P_ui7d3vJpAZeC_2Myd_Kw1XIYpTDxDqjVYck27Xgo=k-no"], "When": "2026-3-9"}, {"Name": "Việt Quốc", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKQ099Olf1YVyhnQsazBLB7ngqAcn6mxee-EvEvl28b-NqnHQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "Đánh giá cao việc sân có bãi đậu xe oto thoải mái và có người trông coi cẩn thận. Mình đi chơi mà ko phải lo lắng gì về xe cộ là thấy an tâm rồi. Giá sân tính ra rất rẻ so với chất lượng mang lại", "Images": null, "When": ""}, {"Name": "thành nguyễn huy", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWqp5P7s1wf9lPXTcvA-TtFXwQPO0RCArx5i5sMGdgPYMll3I8=s120-c-rp-mo-br100", "Rating": 5, "Description": "Nếu ai muốn tìm sân pickleball chất lượng thì qua chỗ ni, khá đáng thử.", "Images": null, "When": ""}, {"Name": "Quang Tran Nhat", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJRc_WbEbX5Hx2iOvmINJ3JDtIJIg5YcKTmHnT6tVAySRiRhw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Greenzone Pickleball là chân ái! Từ giá cả, chất lượng sân đến thái độ phục vụ đều khiến mình hài lòng 100%. Đã đăng ký gói hội viên để tập luyện lâu dài tại đây luôn rồi", "Images": null, "When": ""}, {"Name": "Quoc An", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKetnG59hmnZzyBejFVpRhrDC3ZIGuUMqLHWqrUytFpPhOFUw=s120-c-rp-mo-br100", "Rating": 5, "Description": "", "Images": null, "When": ""}, {"Name": "deptrai toibideptrai", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIBoci_xVK_isn0zSx4QC0KjVFxE5RMLe7j3f68zvqSn5yqUg=s120-c-rp-mo-br100", "Rating": 5, "Description": "Mình hay đánh ca sáng sớm nên thích không khí ở đây. Gió khá thoáng và yên tĩnh nên chơi thể thao rất dễ chịu. Nước uống bán tại sân giá hợp lý chứ không mắc", "Images": null, "When": ""}, {"Name": "Lybien", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIycKy7r8HfDdnDWQGIcsSroCbpyzWg6mp_HxgqjAy-U5ru9w=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân Pickleball này ổn nhất khu này theo cảm nhận của mình. Vạch kẻ khu vực gần lưới rõ ràng, ko bị bong tróc. Anh chủ hay tổ chức giao lưu ghép kèo cho khách lẻ, rất tiện 🤝", "Images": null, "When": ""}]'::jsonb, '{}'::jsonb, NULL, ARRAY['Pickleball court'], NULL, NULL, NULL) ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Duy King Pickleball', '179 Nguyễn Công Trứ, An Hải, Đà Nẵng 550000, Vietnam', 'Da Nang', 'An Hải, An Hai', 16.067767, 108.236473, 4.7, 80, '+84 866 502 927', 'https://www.google.com/maps/place/Duy+King+Pickleball/data=!4m7!3m6!1s0x314219a55e966cc3:0x1e4e9c78da5dc3a1!8m2!3d16.0677671!4d108.2364729!16s%2Fg%2F11wnzk0053!19sChIJw2yWXqUZQjERocNd2nicTh4?authuser=0&hl=en&rclk=1', 'https://datlich.alobo.vn/san/sport_duy_king_pickleball', 'ChIJw2yWXqUZQjERocNd2nicTh4', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGVOYTlSiDdVyb_L7y30pNlIr4pUwCKYuz-qyZZCUco2wsg2Il-aWqMO6QXW74MR0_1xgidnpJKcv4itK5xjNCXoKnEXg6UrSDRXr4FxrxADC_jJYHMkRlpWgOgdsg66tbSZQj-Gytb0YfF=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGVOYTlSiDdVyb_L7y30pNlIr4pUwCKYuz-qyZZCUco2wsg2Il-aWqMO6QXW74MR0_1xgidnpJKcv4itK5xjNCXoKnEXg6UrSDRXr4FxrxADC_jJYHMkRlpWgOgdsg66tbSZQj-Gytb0YfF=w397-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGsxhGJv7T58EDC7l0XVKqAVGW3701X2zQMSfXxn8LBL3QOaS5P3lza4cyCkcDeV84iJ1s7NLm7bstIkYDIIMLo3dI-tojvwzcEVNdf8q_0DzbuSv_OyCCqj255-ESa_EE7N1M=w397-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGNXPX7Hr5YvuNmK2PiIU66xxIh4-1BIRrLIyttzYtqvxY3EVujUCdZ1Ojj0tAFbuYE2SCgI2Z3SuGo4DIXG3DXd1tQiQQU8mNkP6IAoX6j2L-hJ1eYD696JxUeVxGHGndCNvhY_3Tk1sw=w224-h398-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=mIgAGPwsuF15ziw0C6n-vQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=20.300982&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["Open 24 hours"], "Monday": ["Open 24 hours"], "Saturday": ["Open 24 hours"], "Sunday": ["Open 24 hours"], "Thursday": ["Open 24 hours"], "Tuesday": ["Open 24 hours"], "Wednesday": ["Open 24 hours"]}'::jsonb, '[{"Name": "Никита Антонюк", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVeedfjwPOGa9vxNN9KVVvcwED6ctdxhaLqklCIv-tyOshQ973H=s120-c-rp-mo-br100", "Rating": 1, "Description": "Good court, but extremely bad service. 3 times they rescheduled our booking 10 minutes before booked time. If u don’t wanna loose you time — choose another pickleball court", "Images": null, "When": ""}, {"Name": "Damon Stout", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVgO5ACQPhHHhvOOzX2-kXyE-wmHVqxwItX36Bopqcof8_d-AgZ=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Great place to play. Staff is great, but people don''t bring your kids. This isn''t a nursery or a daycare.", "Images": null, "When": ""}, {"Name": "Công Nguyễn", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIU1oNQSkCH2gh2L2NR9Tfl_o7n0IEaGZX3jNom4swdxIeZTB6b=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "Sân khá rộng, đẹp, phí thuê sân rẻ . Có thầy dạy nhiệt tình, vui vẻ. Có cái sân hơi kín, mùa hè mình nghĩ sẽ nóng", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1eMf2GQ27Neivo7gCdeWR5VFhVjNPqCOJ0ZzuuIVG6C2SePCG3a68y9fRdK9CxtBIMYrG3tgKQanj4QECViBNj5cbaKPxxgqx4buK8qAgjOEy9nkb-IdDPXJMtYIlpV_gDo8apeNaCgkQ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1npQANOA2ezX1rRJmwYCN4t0PVwoGu6eyLwTwX8YipF8vZEx2qgIuMWKHoiAkEQEdizI3euFtoRR_E0AutCA-GJpedc5aqFZ3MOBhl-CNu3DNq1c0PAxpW6g2qGHS6LQe9ZQ7adPEmCsMl=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1g4RvJPTKMNd1TsFzN-fIQSKje7hfklV8l8Eh3cU7deL0A76aoN7jHTPXfSAMFoy0xtjNjFEgiLpc5FV7hQFsmP3uhnB0ICHEJMjElVec6E7Zy5v9zt_gH4f9N_R2NQYHTK7KnJaxOl18b=k-no"], "When": "2026-1-3"}, {"Name": "Đức Hoàng", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIETYyI5r_Sr6GoOap0UGfi5uqiPbgoizjFXmap4PuVZEGqEqU=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân rộng, siêu rẻ luôn. Mình mới tập đánh thôi mà được anh chủ sân chỉ nhiệt tình lắm", "Images": null, "When": ""}, {"Name": "Bảo Uyên", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXkkdqXz0PCTGzsK_40uj5rKVuFUo_3j54Wtfsuz2dylehCsqg=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp lắm nha mọi người, giá rẻ mà sân thì lại rộng rãi, là nơi rất hợp lí để giải toả sau những giờ làm việc căng thẳng nè🥰🥰", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3T_LdsV2X61GB0JiSQSgEWMAU-ISE_MhgR_CxjeWzv32L0ByA18RIo_almiaiOKvbTMVI51d8wi9MFfdsq1kOId87nX2ro0IOFpbC_SKuKFvfHC-mIDpl9riFejARUjkPu9NWu1A=k-no"], "When": "2025-3-13"}, {"Name": "Hoàng Võ", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXm2uMc0KqCzexU2anoQH02TOFij9nfkQen_BoKfowdVvuIkiFH=s120-c-rp-mo-br100", "Rating": 5, "Description": "Chất lượng sân tốt, nhân viên nhiệt tình, dễ thương", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3SgX3Y0tpFRw8lO-sMudfivz5CkIwiSVfEd33ydeC4o2LyCmMH25uqR-jhBMvccFIfPZDIDZ6qpS2gmEBBflZxDqN_davGxD7LlKt06hvTaXxDP8LElMx8-9QU7CyHVfTIvywtucRww8M=k-no"], "When": "2026-1-11"}, {"Name": "Ciara Laure", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWDZttu7NIGD26vvTyJc1N9DidWxuSUkEpyMeOWq8EU-cYg2h7c=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân đẹp, sạch khá ok trong tầm giá. Must try 😌", "Images": null, "When": ""}, {"Name": "Thi Doan", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjV85iD6aY0ck8AJ_2xBucdzoTDZB2LVlTtI498GxRhwknq0OLz_=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân trong nhà nhưng thoáng và rộng rãi , đến với sân Duy King pickleball còn có anh hlv chỉ dạy rất nhiệt tình với mức chi phí tốt , recommend mn đến thử và trải nghiệm", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"0": 25, "1": 19, "10": 45, "11": 40, "12": 32, "13": 29, "14": 37, "15": 51, "16": 64, "17": 66, "18": 59, "19": 50, "2": 16, "20": 50, "21": 43, "22": 37, "23": 32, "3": 14, "4": 9, "5": 9, "6": 16, "7": 37, "8": 50, "9": 56}, "Monday": {"0": 19, "1": 11, "10"