INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Trung Tâm Tennis & pickleball Đà Nẵng TTTC cơ sở 1( Tennis court for rent)', '85 Ngũ Hành Sơn, Bắc Mỹ An, Ngũ Hành Sơn, Đà Nẵng 50000, Vietnam', 'Da Nang', 'Bắc Mỹ An, Ngu Hanh Son', 16.045478, 108.239642, 4.9, 34, '+84 943 622 663', 'https://www.google.com/maps/place/Trung+T%C3%A2m+Tennis+%26+pickleball+%C4%90%C3%A0+N%E1%BA%B5ng+TTTC+c%C6%A1+s%E1%BB%9F+1%28+Tennis+court+for+rent%29/data=!4m7!3m6!1s0x314217b65406040d:0xfb5a81af5e52dc46!8m2!3d16.0454777!4d108.2396419!16s%2Fg%2F11vybc7yv8!19sChIJDQQGVLYXQjERRtxSXq-BWvs?authuser=0&hl=en&rclk=1', NULL, 'ChIJDQQGVLYXQjERRtxSXq-BWvs', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAHHjzBHtUrk9uSViwU4b5U1bxAsfCEvJOl3blvJV33T6IaimWA7qH4rsrdT4zeKK1qp4WreANqskaOMvTtKgAHF5B4aaqMVjbcxWGwE0aLx6WohHxUTofkL0oI7r91DUKiQJPxz=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHHjzBHtUrk9uSViwU4b5U1bxAsfCEvJOl3blvJV33T6IaimWA7qH4rsrdT4zeKK1qp4WreANqskaOMvTtKgAHF5B4aaqMVjbcxWGwE0aLx6WohHxUTofkL0oI7r91DUKiQJPxz=w397-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAHyEBU3q8cgtreEzThZUnMRD2fUEPugGp0xKbPvmfb9N3IIqmGEqraPgSgZbSLvgkr5aBUmbxHf96KykJEcoCowiAjxj1_RkTUf55iwNJUnA8q4yuFhLWG1T8pnRpwtysHu5tXM5usK5Z0=w224-h398-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFz4c3BtHzPdexMFW5vQBpxWKvYLn6OFF8BPXV2bQ7uX9d3Nw1q_-qRnYdaAVCbGPfK4_5RI0tGVdZ2H656CZZT-HXBNF2K_lwrmtdG7kw1Ws5PSKxzswUPISyEJB1svIk7M28=w224-h398-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGXzdvYdVpZXcARK90aLll2WQmyQhS61T6OFEhH9oU7PNbsIqYcSppvjoMHVJ6w9UwgZthe4bFYKBol2kmqZtw2Yyg3I233mibUBOBMevnQZ-EgWCHn_Q1-Tjs5ote_XvE4LDjZnmHCEHXK=w298-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=F5idzZjTueyUAMHEMeecug&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=70.65532&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["Open 24 hours"], "Monday": ["Open 24 hours"], "Saturday": ["Open 24 hours"], "Sunday": ["Open 24 hours"], "Thursday": ["Open 24 hours"], "Tuesday": ["Open 24 hours"], "Wednesday": ["Open 24 hours"]}'::jsonb, '[{"Name": "Mina Hertzberg Bakkeli", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLh1wqRsmcP9PvWEOlZZiT-kXJ4SeF1Uoi4Fuf3X5pHVy-YKQ=s120-c-rp-mo-br100", "Rating": 4, "Description": "I took four private lessons here and had a great experience. The coach is patient and attentive, making the sessions enjoyable and productive.\nThe only improvement would be if the coach had stronger English skills to improve our communication.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn2X-3D6QOa4QsDReuK3RVtoW3od85ncGff8DlKmqMRI-2p-dB3qApfy8yux7ZN5rvO3s0NaFY_YoZ60NqpdYRA0V0uWexG1vSNCzTrCVFQXNbtsxPF9nKb2SlBXqLIRtaeP-cUHbw=k-no"], "When": "2025-2-3"}, {"Name": "Duc René van Nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVUa1I__BXpKqdQDkVUwluoprcngX_zzxN1n4MY4h93mIv50CSoNg=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "I come here regularly to play. The court is in a good condition to practice and play. Communication with the owner to book is straightforward. They have sun covers at the back-end of the court that you can pull out to get some shade - it''s a big plus for me. It doesn''t cover the whole court obviously but you can serve nicely from the shade. There''s also the small pickleball nets but I don''t play pickleball.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn180BdoFAl6mMJaL63P90aP-YcQAEDsOTE-msHrCmJMvQphQ8-ZLDat2VipPLCwv6rV4-8Q_qBHF5aCyf-MSf6zOh1zs4H4ZI0L78GMXklBH0HSz0zEFjkipgxr_HKZYt09edU=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3Um3SLzKEn4bfB0Ya7z19ihcAWo4m3ePb9S6O-yBMGvhnzEkVBvbT98rz7cj3CvLLdBzwujm1FjWYacewBK4t09HqBZwbA74k6QVmGyayGRlo73OqODukOmP-TOTF4YH2B_lh5RQ=k-no"], "When": "2025-3-2"}, {"Name": "Lukasz M", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJENKHPWKTTzook5j-pdk8UHyQoOASp43M6v1DTnDB5siDqGQ=s120-c-rp-mo-br100", "Rating": 5, "Description": "As a beginner\nI took around eight tennis lessons here and was very satisfied. The coach focuses on developing good technique and is patient. Good value for money at 600k per private lesson including court rental. The only improvement would be communication as the coach doesn’t speak much English and we needed to rely on google translate. Overall, I highly recommend.", "Images": null, "When": ""}, {"Name": "Hòa Trần", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUvLZU0Mu1mnryjYXJs7t59YdWwTudGgMX0U0uTBI5nzY0f4sSV=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great court, professional and enthusiastic coach. Fun and effective lessons. Worth every penny!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0jtaf6NLIb9wzSFdiBNv7fhX912Xtv8L5r8-fGF1JqJCK3cYeQ5UoZ3Ec0oE79h3JDBuJJ7mWaWIfO4P6hn07pJw4_Q09HJQVN5y6VGXeiz4bUVsET0WwvmwkvMkLsGFwq-WFobmWoZ6IC=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3Wt0sTxgVASv3sCOZ2d11qNxVeGkj_YwfOZpHbG5c9DKwC7ezpSxArp3CKu4sQj9-zMvzV4JXPpeib1G1NO1dFB-qupmO8KrnKtHXdZ-9DCDub19H8kSWra-7j67XXn2dOohn-0kr7mSQ=k-no"], "When": "2025-6-17"}, {"Name": "Art", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL2i5tAcCYrQzOwe82TLnuL1tKOrswO6GxBLGXR_Q24D7bFZw=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "I took a couple of lessons and I was satisfied with the outcomes of every session. The coach is very patient, detail-oriented and highly passionate about getting you to your goals in your tennis game. I’m pleased with the excellent coaching and 💯 recommend his lessons to anyone who’s interested in improving their game.", "Images": null, "When": ""}, {"Name": "Savva Lukhnev", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXrYXNdIuEjApWXeyIketx7QEQPnzrzroOhj4Lp3070get3mns=s120-c-rp-mo-br100", "Rating": 5, "Description": "This tennis court is fantastic! The hard surface provides excellent bounce and consistent play, and the medium coverage adds a great feel to the game. The owner is not only personable but also incredibly responsive, ensuring everything runs smoothly. Plus, having cold water available in the fridge is a thoughtful touch. Highly recommended for a fun and convenient tennis experience!", "Images": null, "When": ""}, {"Name": "Paul Ratiu", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXOe_spFOhre7uigpBEDurc13FfcaviGuPP0El5XS_MbcolRQCb=s120-c-rp-mo-br100", "Rating": 5, "Description": "What a great coach! I’ve had many coaches and went to an academy in the past but he was the best one I had! I liked his focus on the technique. If you’re in Da Nang and looking for a tennis lesson, I would highly recommend going here.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn11mBgHobHOfpaDWuvndKCOipqPg-T9XRwi9xZOlaHm_nvMkcu07ySK9D8d72WajBR7efodORApGecwKSXUeFRnFn_4lSo_IwUhuDhkV9i-2N3lcyWIC4RXvFKojGAi0_U7eYY5PA=k-no"], "When": "2025-4-5"}, {"Name": "bo mun", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLBHoWi10SQeKK04OkGA91wa07mkohFVN60tQlvRJyBtYqs0g=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "I took a 1-hour lesson with my husband and it was full and he is a great coach.  A fun and well-learned time.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1bj5-VEuAzGAyAv6miblcJiE_ME8kzKdGLxfAvnRPlgAJYbV3tjeMZ477jl7jRmQC8LBW9_qpOfQ7lqHMidrX8oEs5kmBKktwlHQnzoSZHt-eD5EjAwDjleLwonMDk5XjewR-9Kw=k-no"], "When": "2024-6-28"}]'::jsonb, '{"Friday": {"0": 62, "1": 37, "10": 31, "11": 31, "12": 18, "13": 25, "14": 25, "15": 56, "16": 62, "17": 93, "18": 75, "19": 56, "2": 31, "20": 43, "21": 56, "22": 87, "23": 81, "3": 43, "4": 37, "5": 43, "6": 43, "7": 37, "8": 43, "9": 37},