INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Summit Hoi An Pickleball Club', '96A Trần Hưng Đạo, Phường Minh An, Hội An, Đà Nẵng 51000, Vietnam', 'Da Nang', 'Phường Minh An, Hoi An', 15.880143, 108.324519, 4.7, 69, '+84 905 747 900', 'https://www.google.com/maps/place/Summit+Hoi+An+Pickleball+Club/data=!4m7!3m6!1s0x31420f01f8f733d7:0xeea359add865bc03!8m2!3d15.8801433!4d108.3245187!16s%2Fg%2F11xgvsf1tf!19sChIJ1zP3-AEPQjERA7xl2K1Zo-4?authuser=0&hl=en&rclk=1', NULL, 'ChIJ1zP3-AEPQjERA7xl2K1Zo-4', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAECr5Zh935Rr8PFAYwmIpql32ULpeIOFfr3U3mzjhXHXc44sZcTh89POhAKCBKFrtdarZBk5tyi7PehmWfx4kO6yeVclcQN9fFZvB56hDKceMHpHcpXW7sRQRB9pz8YGFi_seFkVIt2Wtx2=w408-h306-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAECr5Zh935Rr8PFAYwmIpql32ULpeIOFfr3U3mzjhXHXc44sZcTh89POhAKCBKFrtdarZBk5tyi7PehmWfx4kO6yeVclcQN9fFZvB56hDKceMHpHcpXW7sRQRB9pz8YGFi_seFkVIt2Wtx2=w397-h298-k-no"}, {"title": "Stadium", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFHbku0CgK208mFF5rxx0a7TbdKL13Pnbpwlc4rW8PqphUoDPxmDyD_heD8Fv1Z6QrgfKP9NwuOd5J0jDFGmP4TX84pcidVOgYSvV5VM9yk0eS2cVZStTNt6aXCUC_IqsaQHujp5DdIAZST=w224-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=d1Jz50NaM_m71KLdzD9VNw&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=346.05582&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Edward K", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWifD4-bntMW9g4JZY-4AGQpbCUVnHbhUdk-7HT7r3CCPN7oPd7JQ=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "A very new Pickle ball placed in HoiAn!\nwe love this place. They are very very helpful and nice. The court rooftop can be opened and the toilets are clean. Many beverages to be sold. We would definitely come back here, highly recommended.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0JvK-JD2fHwzpHhMRHUuerB54i1ZLttlwWyOuDRe3tC_o98yp4vhMXrGVdjL2VelOM7yXpkby1iF5t_bmvY5ZXTNEpmLiYDKMtLjMYsGUWfVBjq1B_Dv6Urwc9A_ME0IcLEyMKZ4k1tIvv=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn2GmismN97jTbb2GyhbC0TTJd0x21cMdzTfw-vxiKsI2h2KFTrfqwZLsvla6GG4U7wQQiSXna-NCpL7dV1Rm2EqeOdAxHUyan7TCs9IJqs_W-oG_8aiUo9szyw4WX1Gbcd6QLVs2b_B2KMH=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0xd-x5bQSvb2v-mlDt_4dqZxnRoKpfMMvuxvu67VAG1qwvh1UngpC-8GTztDNiBoWVnJ6IjA1JjiidpPc6cQy8rfrHx0OIZuoNyB4HLWZ6AmInlUB-fQoH5O-EkZGZ-_jOzbARMihmDURR=k-no"], "When": "2025-10-10"}, {"Name": "Theo Tirel", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVn7rtRYc5996npQPKgcvf2SFpOWHjW-l5h77q1A_xMrB4CCg0=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Great place, the staff is very nice. They have many courts, we went with no reservation.\n1hour = 200k (+100k for rackets and balls rental).\nWe had a wonderful time playing there", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1J9hiRXjtYWhgcTc2-iOwhAfaBbxcDybM_D2uPYDQMIfEPSgcKUPq1f3hru6V5F-TsqKBkOa2neCNVjL9Yqziw_QflhMNN73H8KRmTYkojGXLQ3QIBTzQXNcgTsB67YJfsiZG7O3Y1deNK=k-no"], "When": "2025-11-15"}, {"Name": "Nico Conzett", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWSCMDHMUN_vYPGl1BroRqJrpA9tEzv9vAEHPmHDQNupJMjUIsulg=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Nice modern pickleball centre, the staff is super friendly and attentive and has good energy in general. The guy offered me free cold water when he saw I was eating just before playing and also gave us without asking 15 free extra minutes to finish our set. It’s little things but it’s worth mentioning and I appreciate it!", "Images": null, "When": ""}, {"Name": "Smosabi", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKQrc_pF9Gd5ciK-wgNqAfbctnRV27Ygu7AMFI4SbFXabta8w=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Excellent facility with 7 courts. Lighted and has retractable roofs. Since the courts are surrounded by adjacent buildings, it is well insulated from the wind. Hieu, the person who work there, is really nice and hospitable. Location is in the heart of Hoi An tourist area.", "Images": null, "When": ""}, {"Name": "Donna Pacho", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVWB9mv1q_sLrt3pdVaV3wMAuqiCdYi8eZ3vYSIORd05NzYIJ92=s120-c-rp-mo-br100", "Rating": 5, "Description": "Fantastic courts! So easy to book! Right in the middle of Hoi An. Will highly recommend to friends.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn1pCuJRm1TpmlwL-lb6SmZhObrS51S_9N6_p2NaSKbzLpCGvCdkQnMgeBMx6MzaEjVbTurQCO1jmyknF5FTiqfSix1cdeEfMdnPb_lFosAWtBZwVFwGR0XmPh_N8YTnxVv0jxr2tU1uSef2=k-no"], "When": "2026-1-16"}, {"Name": "ella davies", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWpP8fi07tUTQ31-UDETiO8X76lYtkL7d-EPllCXVvWat9HLx9U=s120-c-rp-mo-br100", "Rating": 5, "Description": "Had the best time playing pickle ball, as two tennis playing a who were missing the game whilst travelling. Amazing facilities and great staff. We got to play with a local mother and son, and had so much fun!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn20Q9E4HyhfzSYIvl1PAghLZxzDuRy_PNEVUgyGffg7hsfF1O8H2drSZDK492JGz9SU4rhik4RQstHql7YQ83driQyLhBFHVu3WHDJSFwhu-48rFUxxbbAQrU3btYqcGwxQWRMNA4Mp-Qon=k-no"], "When": "2025-8-8"}, {"Name": "Elizabeth Chapman", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIqDnfuyEufofZMNc6JISGM0itQPVipSd1MNfkWDj8L59GE1A=s120-c-rp-mo-br100", "Rating": 5, "Description": "Amazing court. Great host who’s really nice and friendly!  Had really good fun!", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0Z7XkalqmpsD_uvlYxW1NWSPxAlEDr5h9t8cUwYm9OgziJZZkrVC_WI4R5kKaIeHYaLzcT48QF9T9msZ2loAefEMgcvRdK56PZ5ina8cMo0-S8cfjEL9JqIlkiqAtACqw_K-WseYlGEKM=k-no"], "When": "2026-2-20"}, {"Name": "Trishna Patel", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVtoutz6oYDsETXQegtwXSV0uKCHlEIKuRHBWWJzkOs8JNGHZP9=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "We were in Hoi An for a few days and wanted to play some pickleball. The courts are in great condition and the location was very central. The courts are covered which helps with the heat. No reservations needed. Price was 200.000 for 1 hour, 50.000 for racket and ball rental for 1 hour. Surprised that we were the only ones there on a Saturday morning.", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 55, "11": 45, "12": 50, "13": 40, "14": 45, "15": 40, "16": 60, "17": 65, "18": 75, "19": 60, "20": 50, "21": 30, "4": 0, "5": 25, "6": 55, "7": 70, "8": 90, "9": 70}, "Monday": {"10": 35, "11": 45, "12": 40, "13": 30, "14": 35, "15": 50, "16": 55, "17": 60, "18": 40, "19": 35, "20": 30, "21": 40, "4": 0, "5": 30, "6": 35, "7": 30, "8": 25, "9": 35}, "Saturday": {"10": 45, "11": 55, "12": 55, "13": 50, "14": 30, "15": 25, "16": 20, "17": 20, "18": 30, "19": 45, "20": 55, "21": 60, "4": 0, "5": 40, "6": 30, "7": 25, "8": 35, "9": 45}, "Sunday": {"10": 60, "11": 55, "12": 40, "13": 30, "14": 35, "15": 40, "16": 45, "17": 45, "18": 30, "19": 20, "20": 25, "21": 40, "4": 0, "5": 25, "6": 20, "7": 25, "8": 35, "9": 40}, "Thursday": {"10": 20, "11": 15, "12": 25, "13": 30, "14": 45, "15": 50, "16": 85, "17": 100, "18": 85, "19": 40, "20": 30, "21": 40, "4": 0, "5": 25, "6": 15, "7": 15, "8": 20, "9": 25}, "Tuesday": {"10": 40, "11": 35, "12": 40, "13": 55, "14": 75, "15": 55, "16": 35, "17": 30, "18": 35, "19": 50, "20": 50, "21": 30, "4": 0, "5": 75, "6": 65, "7": 85, "8": 65, "9": 60}, "Wednesday": {"10": 40, "11": 40, "12": 35, "13": 30, "14": 20, "15": 30, "16": 35, "17": 40, "18": 50, "19": 40, "20": 50, "21": 30, "4": 0, "5": 25, "6": 30, "7": 50, "8": 45, "9": 45}}'::jsonb, '[{"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}]'::jsonb, ARRAY['Sports club', 'Washroom'], NULL, '05:00', '22:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
