streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=IHdkITHXOphb3yNoBgiCEQ&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=84.00259&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–10 p.m."], "Monday": ["5 a.m.–10 p.m."], "Saturday": ["5 a.m.–10 p.m."], "Sunday": ["5 a.m.–10 p.m."], "Thursday": ["5 a.m.–10 p.m."], "Tuesday": ["5 a.m.–10 p.m."], "Wednesday": ["5 a.m.–10 p.m."]}'::jsonb, '[{"Name": "Scott Katz", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocK2XCIbTsOyZZxrRnViomzES6sjWrgTOjg3h5fS5shQOWlBTA=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "I dropped in as an expat. who speaks little Vietnamese.  I was treated with incredible kindness by the manager and by all of the players.  I was loaned a racquet and patiently guided into games with players of matching skill.  I was even given a free banana. 😉", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3-Dv24gS7F_D33Jx_sufgT1ooXGNh1KRRQSgFEIbfmM3Royb9SrMqusM61GF34J1kP5HMKsvnOW8U6IEvXUyjASMC6bt4tRIsFTaPPm6ff6gmL9YJNuXFallTQtes5QLfqgd1w-2CzY9QR=k-no"], "When": "2025-10-31"}, {"Name": "Trung Hiếu Trần", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXsW2lXswMFcpPp4rfKiraF740eIFivxpehqyuu9AHuHuKR5sh7=s120-c-rp-mo-br100", "Rating": 5, "Description": "I just had a wonderful experience at this pickleball court and would like to share some highlights!\n\nThe court attracts many talented athletes with impressive skills. The matches are very lively and competitive. I learned a lot from their playing style and felt inspired to improve my own skills.\n\nThe owner of the court is very friendly and enthusiastic. They are always ready to assist and advise players. Their enthusiasm truly creates a positive atmosphere and encourages everyone to participate.\n\nThis pickleball court is not only a place to play sports but also a place to connect with others. The community here is large and welcoming, providing opportunities to meet and make friends with those who share the same passion. The social events and activities are also very enjoyable and enriching.\n\nIn summary, if you are looking for a place to play pickleball, this court is an excellent choice. I will definitely be coming back frequently!", "Images": null, "When": ""}, {"Name": "T Tran", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWjEMG2LE5GRMq16rkK4dnC722n8gfpcXraZIL36noluwRzKarb=s120-c-rp-mo-br100", "Rating": 5, "Description": "Very friendly welcoming staff and members of the facility. Whether you are newbie or skillful players. This club has capability to accommodate what you need. The courts are spacious, good parking. Convenient location, near airport, Con market and shopping center. We love it.", "Images": null, "When": ""}, {"Name": "Toan Ng", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLXU5Pdp4fXdja2lDnBDIWX7U6NugBDnpIOchoGaEeYc7FMYw=s120-c-rp-mo-br100", "Rating": 5, "Description": "The owner Tri is a nice guy and was very welcoming. The people there were super friendly and accommodating even though we barely spoke any Vietnamese and are from overseas. Would highly recommend this Pickleball club regardless of skill level.", "Images": null, "When": ""}, {"Name": "Mark Nishiyama", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWJJetCvZKo9bKg46g4wMdk-N7KHCfilNH_WLZwjBHuA9a4rn9-3Q=s120-c-rp-mo-br100", "Rating": 5, "Description": "Very nice place to play open pickleball. Thank you 👍", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3RFq1dZYTmGHpHTAQbz65Mi8RjrWG6CgpGfGNxnK83Bn6v3-tActVIu_qZQKRJknMiakKAbbp2CzD06Fen6OuX7qSewug4YRfB9wT7qoHuyx70KteZusCBMPqgw_g4gfkmk6q9=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1m1GrzyQAq3RAuiOP8UtIlrKMGX1awkhL1horG4aSdWgnO-T3ZWTqHO0iGgAzKFreU88SJ4isy2YKFurOe-4YebibKIvVtUegdccqBTSrJMRb81WCV2h4Mx3ZFOhU-sWe_QJh6=k-no"], "When": "2025-1-5"}, {"Name": "phuc nguyen", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJKsanuGVbmhuAyMaL9hgd-7WSu3vyHuRn4z7cjNvBZK2qwuQ=s120-c-rp-mo-br100", "Rating": 1, "Description": "Sân không quản lý được lượng người đánh, đánh social bình chọn đăng ký đánh lên 2 sân mà hơn 20 người, thành viên trong nhóm social mà 1 ngày đẹp trời tự nhiên bị kích ra không lý do.", "Images": null, "When": ""}, {"Name": "Tán Văn Hải", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVBZl4G7l4eQvOh2Sy_ZpF3lIY2YEF9Wbo9XaJRtnrGT2ULIi65Gw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Sân Pickleball Thanh khê quá đỉnh lun, Sân thoáng mát, Mặt sân phẳng, bề mặt có độ bám phù hợp, vạch kẻ rõ ràng theo đúng chuẩn pickleball. Sân có hệ thống đèn chiếu sáng tốt, chơi buổi tối vẫn đảm bảo tầm nhìn rõ ràng. 10 đỉm ko có nhưng, mọi người nên đến trãi nghiệm nha...🫰😍", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn07bsmvmx2qJbxSZVLCqyGAYZmfvgVdGGe1mjUB0fEZzATxfv-bx6L_u3fto-ZdXABpiqkCOpuEGYrBrMFCPaoCpwYPV6Sgu4OQRLYFct-JOFUaiM19rPJ66jPIPTCCwO1vDySswo2x2PwJ=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3nWRREYVBnPXCWLlqx7JDASrE_3VQhnoxdwapSZkUEE_GHaXIYjrOZ09zb7eHVI71XXMJ_ZNr10r0p3JP4oLle7NXKFfa7DrLH3hyq63HbzX0WknY74gmicyQTVbzrkq3GAkD_5MrI6nw=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1WMJ3HNDGmisJPVdCMybToxex4w8RbfNz9x_ZU3-yLKp-CFmWjyO6N1A1EsKMdxbWKPeVp9eMWVw2jVn0D_smtFWERk8S1Q20YySdYJJHl1trpAmCoEr4BM_7H-ZNTgG_87WDqRjXACP2f=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn07jVTKDRh9L1eYS1haKNrA6U9V991KXjGHwcxAwBo2P5J5oo-4U7jzh6PEqhf9ithLsZVJA4Cxpa0ZFez2wEWYGmy7EF8962ZpBw1a-x3comqPyM_GaX5-kLK0SN7BmS0YadOloFVbzWdj=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1jOYXGynKgNMt053GN4lmK3aO06k68UJ72jNukBIo4_1jeFGgxxA2zIC1aMgy2felQ_tBKUygPNPCPkzl4ZpxL4zg2I4_82oe3HNHbglib8FrWwFySBQY6vCzm1k8UJwce9hISYjhqp4Rt=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn0QTRVDI_ucplhKHIWmF6jDBFqs-offBU2mDvuLmp3TAwcRtdTn-ABP-7JiJD5l66f0s3jXaIpo2WuSLzXuqNHn4PKCfulrfl5eFvpNM8dvLm0E3OESI9CIvA-TBi8ukR88AJEOf1AzLdvg=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn1faR9myopKyZM3hqnjFtcH2jgSAMvxy1Jn1ptR0Os4ulQ7aKS14RJc7GJGR78sjJii96trzlZnbJXs-cpsDgtNgtnpaDdn_uS3S44pksBfH5Pxs5n5FaNj2zZ2xIy6z1WhyuLZoaaTwZpD=k-no"], "When": "2025-6-21"}, {"Name": "Vinh Hoàng Trần", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjVqqx6oI61GFN2bFUrH3GAVrWsvgEmECRZsUo6B0_swX2SqVcuvFw=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Chủ sân thân thiện. Sân đầu tiên gần khu vực Hà Huy Tập và Trần Cao Vân. Hàng tuần đều có chơi Social rất vui hầu hết mọi lứa tuổi...", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3621NU6CjDATlWJg_9SxpDuGtSkah4Avx6DGE2J10qq8ecGjsM2Xh-hv_L1UnPGDZNPhRmrqcakg3gfEgb3CRXdrb8bTJ-wiDitPU0vzUvolOLJJ0dJA5D1BLVuZ53Tv5IXAwKjg=k-no"], "When": "2024-11-19"}]'::jsonb, '{"Friday": {"10": 41, "11": 44, "12": 44, "13": 44, "14": 50, "15": 50, "16": 52, "17": 73, "18": 76, "19": 85, "20": 79, "21": 61, "4": 0, "5": 73, "6": 67, "7": 52, "8": 35, "9": 32}, "Monday": {"10": 38, "11": 32, "12": 44, "13": 50, "14": 61, "15": 58, "16": 55, "17": 55, "18": 61, "19": 61, "20": 64, "21": 52, "4": 0, "5": 64, "6": 64, "7": 55, "8": 52, "9": 41}, "Saturday": {"10": 67, "11": 67, "12": 38, "13": 23, "14": 23, "15": 38, "16": 61, "17": 61, "18": 67, "19": 64, "20": 58, "21": 50, "4": 0, "5": 47, "6": 35, "7": 32, "8": 26, "9": 47}, "Sunday": {"10": 47, "11": 41, "12": 26, "13": 38, "14": 52, "15": 73, "16": 94, "17": 100, "18": 91, "19": 70, "20": 55, "21": 50, "4": 0, "5": 44, "6": 58, "7": 61, "8": 58, "9": 61}, "Thursday": {"10": 35, "11": 41, "12": 50, "13": 52, "14": 64, "15": 70, "16": 79, "17": 76, "18": 76, "19": 67, "20": 67, "21": 58, "4": 0, "5": 41, "6": 50, "7": 44, "8": 35, "9": 29}, "Tuesday": {"10": 64, "11": 55, "12": 52, "13": 50, "14": 52, "15": 67, "16": 76, "17": 88, "18": 97, "19": 94, "20": 94, "21": 73, "4": 0, "5": 35, "6": 41, "7": 41, "8": 44, "9": 50}, "Wednesday": {"10": 32, "11": 29, "12": 35, "13": 35, "14": 47, "15": 67, "16": 73, "17": 82, "18": 82, "19": 70, "20": 67, "21": 50, "4": 0, "5": 35, "6": 38, "7": 41, "8": 35, "9": 29}}'::jsonb, NULL, ARRAY['Club'], NULL, '05:00', '22:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('Pickleball Song Han', '17 Lê Duẩn, Hải Châu, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Hai Chau', 16.071177, 108.221696, 4.1, 40, '+84 799 900 001', 'https://www.google.com/maps/place/Pickleball+Song+Han/data=!4m7!3m6!1s0x314219003c853237:0x9e9bb4f262c7d1f5!8m2!3d16.0711766!4d108.2216964!16s%2Fg%2F11wj4xvnlh!19sChIJNzKFPAAZQjER9dHHYvK0m54?authuser=0&hl=en&rclk=1', 'https://www.facebook.com/share/1ECiJ5eUhZ/?mibextid=wwXIfr', 'ChIJNzKFPAAZQjER9dHHYvK0m54', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAFIgAERtZBfpKscTXaaHbBUlPo7sA4uwJ6PcEQA5VdSJzo-tQ0jIwXkGvwZy_4eTHd0CYWaaXVcX_K40FyxUHi55bdN1S-Sjt9iO3_Y8WIwSw0ahVSsWTSc0RI0vHM418c_lJ_R6P6aPrk=w408-h543-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAFIgAERtZBfpKscTXaaHbBUlPo7sA4uwJ6PcEQA5VdSJzo-tQ0jIwXkGvwZy_4eTHd0CYWaaXVcX_K40FyxUHi55bdN1S-Sjt9iO3_Y8WIwSw0ahVSsWTSc0RI0vHM418c_lJ_R6P6aPrk=w224-h298-k-no"}, {"title": "Latest", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGtIz0MKuaEMEeanWdurQn3wzAKE-yONdd97VRJhGr0GwllZ1wHRare477oSxtkt0GjjUG7ao-5C7hZ48jGuwCXWy2kdhTxf9kFpvTLZqXls9Uy6Z_sz9HD5Q1UV551TFmTYe7iTbqCq63G=w224-h298-k-no"}, {"title": "Videos", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEXOPuyqyyD39774dveQa_mjIgxrZg06zcCaKNGVjsvR3Sg7XYtBmWU_oYOX51x6pSpG937mnLZ7KbAjtplUYQSTJMQMjtR9LN17uDIJUu9v9ylcX6f62B2Z5KLdLH9IeEJ0MlWTdek3Oo=w529-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAEpMMG8Tp4ZWXTvcYmMhpeU6G5j-DJ73St4-ewkzClpft5U1IPQpqr_1fEIW_z-DJTHUa78e2N5k2f3Ul7ZgSmd9Gp76aEU_MQ96WmiQnSlTBdk17dqjEd5sHhslJeRq8q4kSE9CK_PyArJ=w224-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=iYfdr3Ffz8tNo9zUz8oP3g&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=172.37248&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–11 p.m."], "Monday": ["5 a.m.–11 p.m."], "Saturday": ["5 a.m.–11 p.m."], "Sunday": ["5 a.m.–11 p.m."], "Thursday": ["5 a.m.–11 p.m."], "Tuesday": ["5 a.m.–11 p.m."], "Wednesday": ["5 a.m.–11 p.m."]}'::jsonb, '[{"Name": "Honest Evaluator", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWRTHjeBNz0rJxFJvTbab2HJqAOR1IbWS6aCHnECxlIsO4mMD8=s120-c-rp-mo-ba4-br100", "Rating": 3, "Description": "Hot. Needs better ventilation.\nQuite difficult to play in the heat.\n\nThe dividers between the courts are quite low, often the ball ends up outside of the court.\n\nStaff are nice.", "Images": null, "When": ""}, {"Name": "Michael Ferrer", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJpwvZGgoyGX9BZb-cpxI-00yW8w6TmlLrxGkjhxlD4-iC2uZs=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place and super helpful owner they let me test out my new paddle for 30 minutes.", "Images": null, "When": ""}, {"Name": "David", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXi7Sv6YZITfuoWtrXEQoGzkPKS9sIvkwnkrw5ygJfpO6mLO0NQ=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "This is my second review. The first one wasn''t all that great. But they have a new manager who is supervising the social play and he''s doing a great job. So, brand new courts, all very nice. All the courts are covered so if it''s raining we can still play. They have about 6\\7 courts. It''s pretty busy so I would suggest to reserve a court.\n\nThank you for your time.", "Images": null, "When": ""}, {"Name": "Keith Hall", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU2ktQBP_yimCf8n0fQr5aOJId9XoiNLhlBMhoXswJr0EijgiiI=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "I had a very good time at this pickleball court today. I found the manager very helpful and the other players very friendly.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn3IuBBa2oCmPZBJu5e0MZrKKBizBV8wL-zIGjpQS9vXq2efiULLsjxMJqIhg4LTVG2USRf6CpzB-IewBcARPjiXNtDJU1eyklpcCUfUMralssaVD6A2DdeKWhvR5T7B7lQLb9yx_c7vzBKC=k-no"], "When": "2025-10-30"}, {"Name": "Débora Pellens", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocLJZkrwEXhT2kN_ot1yAA9cKIYQpljHrtLbROYwj2kj0un9dw=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "This place is horrible. We came to play and the owner kept making fun of my friend because of her weight. Then he brought out a scale for her to weigh herself and started laughing at her. Unbelievable — I do not recommend this place.", "Images": null, "When": ""}, {"Name": "Maria helena Correa", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKBpsMNwy-hgH38YHO5fdB4pPVod7D-Xflwhqp6-rNJEE_yHw=s120-c-rp-mo-ba2-br100", "Rating": 1, "Description": "I had a deeply disappointing experience at this place. I was treated with clear prejudice and disrespect. It’s shocking how unwelcoming and judgmental the environment was. If you’re not a local or don’t fit their narrow standards, I strongly suggest you stay far away from this place. Discrimination has no place in sport — or anywhere.", "Images": null, "When": ""}, {"Name": "A Ng", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjUQfIs8m4PWX-84C3ETZr5k2l1nSMCCWQZgfbwzC-gN_on4FtkFJQ=s120-c-rp-mo-ba5-br100", "Rating": 5, "Description": "I have nice experience here", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn0XbokKOcav_IbmgF71llAlEFNjY1R0HdZ9ReYOcJb-0IHwFWgQHs8anETZTte5atZQ0jMP58p06HRfKfYKvTwLXBczCGZ1Ebt7nLBf7mlmTetTKvx0pclLEbORQos_pdM4vjcaYBwdIDw=k-no"], "When": "2025-10-8"}, {"Name": "Henry T", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocKlb3PDVKyKTiXYCe7tN3KqvKBMA3cq1zqAIdS5UO8N7a1_mw=s120-c-rp-mo-br100", "Rating": 5, "Description": "Great place to get your pickleball fix, strongly recommended!", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 32, "11": 27, "12": 25, "13": 27, "14": 25, "15": 32, "16": 35, "17": 52, "18": 50, "19": 47, "20": 42, "21": 37, "22": 32, "4": 0, "5": 15, "6": 25, "7": 35, "8": 40, "9": 37}, "Monday": {"10": 37, "11": 37, "12": 30, "13": 22, "14": 22, "15": 32, "16": 47, "17": 67, "18": 87, "19": 100, "20": 92, "21": 72, "22": 40, "4": 0, "5": 35, "6": 37, "7": 32, "8": 32, "9": 35}, "Saturday": {"10": 35, "11": 40, "12": 32, "13": 35, "14": 35, "15": 55, "16": 57, "17": 50, "18": 42, "19": 35, "20": 27, "21": 27, "22": 30, "4": 0, "5": 10, "6": 22, "7": 35, "8": 45, "9": 40}, "Sunday": {"10": 27, "11": 22, "12": 22, "13": 30, "14": 47, "15": 62, "16": 65, "17": 60, "18": 52, "19": 45, "20": 37, "21": 32, "22": 27, "4": 0, "5": 32, "6": 37, "7": 45, "8": 40, "9": 32}, "Thursday": {"10": 52, "11": 57, "12": 52, "13": 52, "14": 52, "15": 70, "16": 82, "17": 87, "18": 90, "19": 75, "20": 57, "21": 52, "22": 37, "4": 0, "5": 32, "6": 40, "7": 37, "8": 35, "9": 40}, "Tuesday": {"10": 47, "11": 37, "12": 30, "13": 30, "14": 47, "15": 65, "16": 82, "17": 85, "18": 80, "19": 55, "20": 40, "21": 30, "22": 17, "4": 0, "5": 25, "6": 25, "7": 22, "8": 32, "9": 40}, "Wednesday": {"10": 27, "11": 42, "12": 37, "13": 40, "14": 32, "15": 27, "16": 30, "17": 45, "18": 60, "19": 62, "20": 50, "21": 40, "22": 27, "4": 0, "5": 22, "6": 27, "7": 30, "8": 27, "9": 27}}'::jsonb, '[{"id": "amenities", "name": "Amenities", "options": [{"name": "Washroom", "enabled": true}]}]'::jsonb, ARRAY['Washroom', 'Athletic club'], NULL, '05:00', '23:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
INSERT INTO public.courts (name, address, city, district, lat, lng, rating, rating_count, phone, google_maps_url, booking_url, place_id, thumbnail_url, images, opening_hours, reviews_data, popular_times, amenities, tags, highlight, hours_open, hours_close) VALUES ('PICKLEBALL BIÊN PHÒNG ĐÀ NẴNG', '2-3 Hoàng Sa, Thọ Quang, Sơn Trà, Đà Nẵng 550000, Vietnam', 'Da Nang', 'Thọ Quang, Son Tra', 16.095548, 108.251836, 5.0, 8, '+84 383 046 469', 'https://www.google.com/maps/place/PICKLEBALL+BI%C3%8AN+PH%C3%92NG+%C4%90%C3%80+N%E1%BA%B4NG/data=!4m7!3m6!1s0x314217002756a03d:0x7d27245a432b4b35!8m2!3d16.095548!4d108.251836!16s%2Fg%2F11ypqpbr10!19sChIJPaBWJwAXQjERNUsrQ1okJ30?authuser=0&hl=en&rclk=1', NULL, 'ChIJPaBWJwAXQjERNUsrQ1okJ30', 'https://lh3.googleusercontent.com/gps-cs-s/APNQkAGaBh9UeuV_QbTB9i3q1E7YU7krSC7igI-Bd4Zl-pEvco-XHaIMYnV1Omg_UkAAJ7zlBIiD8LAHzZOU6kgIXahUZyrT-Wz06j0rl74DmZZafE4CErt-wK7aPSth_sYprUfunXcqdq02ANKb=w426-h240-k-no', '[{"title": "All", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAGaBh9UeuV_QbTB9i3q1E7YU7krSC7igI-Bd4Zl-pEvco-XHaIMYnV1Omg_UkAAJ7zlBIiD8LAHzZOU6kgIXahUZyrT-Wz06j0rl74DmZZafE4CErt-wK7aPSth_sYprUfunXcqdq02ANKb=w529-h298-k-no"}, {"title": "By owner", "image": "https://lh3.googleusercontent.com/gps-cs-s/APNQkAG6bBuPEEn2lGBMPEXujfb1Vb58NqrkN5CBaJNIBm_S6LYNfRG45_6-qDSPfvyJrSL4ZNKfiOm_ZYsLa4T1pKZ1_naX4A_yOegXQ7x1dhBycT6RmajaS8DnLQVyutIbbfn4LvpOOrso0tmO=w531-h298-k-no"}, {"title": "Street View & 360°", "image": "https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=1dPvGjnSS32Wwb528Yd47g&cb_client=maps_sv.tactile.gps&w=224&h=298&yaw=293.65924&pitch=0&thumbfov=100"}]'::jsonb, '{"Friday": ["5 a.m.–9 p.m."], "Monday": ["5 a.m.–9 p.m."], "Saturday": ["5 a.m.–9 p.m."], "Sunday": ["5 a.m.–9 p.m."], "Thursday": ["5 a.m.–9 p.m."], "Tuesday": ["5 a.m.–9 p.m."], "Wednesday": ["5 a.m.–9 p.m."]}'::jsonb, '[{"Name": "B Peters", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjXAPGRC6mJR-5eA7-mWxn3PU4yLe94ToWiPbqrwiAWObe_iXf9tBA=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Inexpensive place to play, although not the cleanest facility.  The floors could use a good scrubbing.  The ventilation is just ok, not great as some have reported.  There were some players smoking during warm-up or play.  That was a first for me!  It''s a little arbitrary as to which player(s) go next.  But, I''ve noticed this is the case for many places in Danang.  Overall, decent and we played here a few times while staying in Danang.  The owner is very nice and hospitable!", "Images": null, "When": ""}, {"Name": "Claudi Michi Wandervogel", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL_p8viZTKTH84kzli9ouZq2cuHrTcNkpxiKMaT6XgNY5PvMg=s120-c-rp-mo-ba4-br100", "Rating": 5, "Description": "Toller Platz. 4 Innen- und 5 Aussenplätze. Sehr freundliche Mitarbeiter und Spieler.", "Images": ["https://lh3.googleusercontent.com/grass-cs/ANxoTn25N-J-Xu6_WOEk1RshnpIbj3fwECEdgWlWr-VpRgoGfW_6YqMU0guKMMuwxYMUjUFNM3lGi-yeYlj6dDTQhZBhLY2VOYqjqvHe79EIrIrEjA-RHBgMw_T_AlNT8k3nuOtWp6KTIFaUdmsL=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3vdXc2cJweS60g0whDDGvb5iJWpvkMExKvHq4oBfrzBkin9VgPIaniETz61bgRc9Zi__P_NfZjAIGLeQ3u7-T9npiKujqfEc4Z1-5ba7OH5lXI7dfTcu9bPLpQqlMqRx8_VqQEa7kYeEO1=k-no", "https://lh3.googleusercontent.com/grass-cs/ANxoTn3MKv67HuakNkHypM-EcpPE3ECpO7mkGkRpu9remI27-dB0KcEE8buhP1fO9kyd-3wjT3Upbfnz-6uR5a2-gxoEFIeot50Px-wsuEz__abMXjD_D6GeSsroGvXNL9f70TnXoUV8wEXHOh8=k-no"], "When": "2026-1-23"}, {"Name": "Geeta Bhagavati", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocL8fqfxGNyosyTK5C0OyzQDUN_xlVS3IUqxXNMTVCsoWvQAGA=s120-c-rp-mo-br100", "Rating": 5, "Description": "Хороший корт. У моря, помещение открытое, хорошо продувается ветром. По сути это открытый корт под навесом. Совсем открытый, без крыши, тоже есть. Пиклбол и теннис.\nПриятный отзывчивый персонал. Есть ракетки в аренду. Можно бронировать корт заранее через зало.\nМного свежего воздуха!!!", "Images": null, "When": ""}, {"Name": "Svetlana Tkachenko", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocIRCjW9T6hFc09zkae3_yXmlqT5GRhNU0Xt0tK4N88Pti3lew=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Забронировали вчера корт через зало. Сегодня с утра мне написали и предложили перебронировать из-за сильного дождя. Это было очень мило с их стороны, клиентоориентированность 👍. Корт хороший и чистый, продуваемый.", "Images": null, "When": ""}, {"Name": "anh mr", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjU9EfqhiwMYGS7hDM404jlq5ut8PCtOMvxz9Ltb26cTrneKEHrw=s120-c-rp-mo-br100", "Rating": 5, "Description": "8 sân cả trong nhà ngoài trời", "Images": null, "When": ""}, {"Name": "Bap Cui", "ProfilePicture": "https://lh3.googleusercontent.com/a-/ALV-UjWRENrk6tcsZ241sEZMI4p9sZHFQSzIskxOMzKKzt_h2ei1Jilq=s120-c-rp-mo-ba3-br100", "Rating": 5, "Description": "Sân rộng, thoáng. Chỗ để xe rộng.", "Images": null, "When": ""}, {"Name": "Lukas Schmucken", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJxcJltbWl7b7Ztk3kKJBs64mNuJhWSTeBbP9xP6c0n8Tz2Zw=s120-c-rp-mo-ba2-br100", "Rating": 5, "Description": "Schoene Anlage, gute Preise und nette Leute. Und natuerlich Huda", "Images": null, "When": ""}, {"Name": "Dang Truong Binh", "ProfilePicture": "https://lh3.googleusercontent.com/a/ACg8ocJELUME_YRHbfvF3FJgG6dc7W66H58CSJusTxKgHfqworlJSA=s120-c-rp-mo-br100", "Rating": 5, "Description": "", "Images": null, "When": ""}]'::jsonb, '{"Friday": {"10": 35, "11": 27, "12": 25, "13": 22, "14": 30, "15": 52, "16": 77, "17": 100, "18": 97, "19": 82, "20": 62, "21": 0, "4": 0, "5": 12, "6": 25, "7": 32, "8": 42, "9": 35}, "Monday": {"10": 32, "11": 30, "12": 32, "13": 52, "14": 67, "15": 85, "16": 92, "17": 92, "18": 85, "19": 70, "20": 50, "21": 0, "4": 0, "5": 12, "6": 10, "7": 10, "8": 15, "9": 25}, "Saturday": {"10": 35, "11": 37, "12": 25, "13": 35, "14": 45, "15": 65, "16": 77, "17": 80, "18": 70, "19": 47, "20": 42, "21": 0, "4": 0, "5": 30, "6": 30, "7": 35, "8": 32, "9": 37}, "Sunday": {"10": 42, "11": 35, "12": 30, "13": 30, "14": 37, "15": 55, "16": 57, "17": 62, "18": 42, "19": 35, "20": 22, "21": 0, "4": 0, "5": 20, "6": 25, "7": 22, "8": 27, "9": 32}, "Thursday": {"10": 47, "11": 40, "12": 30, "13": 27, "14": 37, "15": 55, "16": 80, "17": 97, "18": 92, "19": 65, "20": 40, "21": 0, "4": 0, "5": 35, "6": 37, "7": 37, "8": 45, "9": 47}, "Tuesday": {"10": 30, "11": 22, "12": 15, "13": 17, "14": 37, "15": 65, "16": 87, "17": 95, "18": 82, "19": 55, "20": 35, "21": 0, "4": 0, "5": 17, "6": 27, "7": 42, "8": 42, "9": 35}, "Wednesday": {"10": 27, "11": 32, "12": 25, "13": 25, "14": 25, "15": 50, "16": 75, "17": 92, "18": 80, "19": 57, "20": 37, "21": 0, "4": 0, "5": 15, "6": 12, "7": 15, "8": 15, "9": 25}}'::jsonb, NULL, ARRAY['Pickleball court'], NULL, '05:00', '21:00') ON CONFLICT (place_id) DO UPDATE SET name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, district = EXCLUDED.district, lat = EXCLUDED.lat, lng = EXCLUDED.lng, rating = EXCLUDED.rating, rating_count = EXCLUDED.rating_count, phone = EXCLUDED.phone, google_maps_url = EXCLUDED.google_maps_url, booking_url = EXCLUDED.booking_url, thumbnail_url = EXCLUDED.thumbnail_url, images = EXCLUDED.images, opening_hours = EXCLUDED.opening_hours, reviews_data = EXCLUDED.reviews_data, popular_times = EXCLUDED.popular_times, amenities = EXCLUDED.amenities, tags = EXCLUDED.tags, highlight = EXCLUDED.highlight, hours_open = EXCLUDED.hours_open, hours_close = EXCLUDED.hours_close;
